const items = [];
for (const item of $input.all()) {
  const newItem = {...item};
  if (newItem.binary) {
    for (const key of Object.keys(newItem.binary)) {
      const bin = newItem.binary[key];
      const fileName = bin.fileName || '';
      const ext = fileName.split('.').pop().toLowerCase();
      const mimeMap = {
        'pdf': 'application/pdf',
        'doc': 'application/msword',
        'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'xls': 'application/vnd.ms-excel',
        'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'txt': 'text/plain',
        'csv': 'text/csv',
      };
      if (mimeMap[ext]) { bin.mimeType = mimeMap[ext]; }
      newItem.json.fileExt = ext;
      newItem.json.isExcel = (ext === 'xlsx' || ext === 'xls');
    }
  }
  items.push(newItem);
}
return items;

const embResponse = $input.first().json;
const embedding = embResponse.data[0].embedding;
const userText = $('Telegram Trigger').item.json.message.text;

return [{json: {
  query_embedding: embedding,
  match_threshold: 0.0,
  match_count: 5,
  filter: {},
  _userText: userText,
}}];

// Format context from search results
const items = $input.all();
const userText = $('Подготовить RPC').first().json._userText;
const chatId = $('Telegram Trigger').first().json.message.chat.id;

let context = '';
let hasResults = false;

for (const item of items) {
  const content = item.json?.content;
  if (content && content.length > 5) {
    context += content + '\n\n';
    hasResults = true;
  }
}

if (!hasResults) {
  context = 'В базе знаний нет релевантной информации по этому вопросу.';
}

const chatInput = `Контекст из базы знаний:\n${context.trim()}\n\nВопрос пользователя: ${userText}`;

return [{json: {
  chatInput: chatInput,
  _chatId: chatId,
}}];

// Collect all Excel rows into a single GPT prompt
const rows = $input.all();
const fileName = $('Telegram Trigger').first().json.message?.document?.file_name || 'excel';
const jsonData = rows.map(r => r.json);

// Trim to fit context window (max ~15k chars of data)
let dataStr = JSON.stringify(jsonData, null, 0);
if (dataStr.length > 15000) {
  dataStr = dataStr.slice(0, 15000) + '... (truncated)';
}

const prompt = `Преобразуй данные из Excel-файла "${fileName}" в читаемый текст для базы знаний.

Данные (JSON, каждый объект = строка таблицы):
${dataStr}

Правила:
- Определи тип таблицы: график производства, прайс-лист, отчёт, справочник
- Для графиков производства: "Продукт: прокат [даты] [месяц] [год]"
- Для прайсов: "Продукт | Цена | Единица"
- Разбей на фрагменты по 10-15 строк
- Каждый фрагмент должен содержать заголовок/контекст (название файла, тип данных)
- Верни JSON массив строк: ["фрагмент 1", "фрагмент 2", ...]
- НЕ добавляй комментарии вне JSON`;

return [{json: {
  model: 'gpt-4o-mini',
  messages: [
    {role: 'system', content: 'Ты помощник для обработки таблиц. Отвечай строго JSON массивом строк. Никакого текста вне JSON.'},
    {role: 'user', content: prompt}
  ],
  temperature: 0.1,
  max_tokens: 4000
}}];

// Parse GPT response into chunks for embedding
const response = $input.first().json;
const rawContent = response.choices[0].message.content;
const fileName = $('Telegram Trigger').first().json.message?.document?.file_name || 'excel';

// Strip markdown code fences (```json ... ```)
let content = rawContent.trim();
const fenceMatch = content.match(/^```[a-z]*\n([\s\S]*?)\n?```$/);
if (fenceMatch) {
  content = fenceMatch[1].trim();
}

let chunks;
try {
  const parsed = JSON.parse(content);
  chunks = Array.isArray(parsed) ? parsed : [String(parsed)];
} catch (e) {
  // Fallback: split by double newline
  chunks = content.split(/\n\n+/).filter(c => c.trim().length > 10);
  if (chunks.length === 0) chunks = [content];
}

// Filter out empty chunks
chunks = chunks.filter(c => String(c).trim().length > 5);

return chunks.map((text, i) => ({
  json: {
    text: String(text).trim(),
    metadata: JSON.stringify({source: fileName, chunk: i + 1, total: chunks.length, type: 'excel_gpt'})
  }
}));

// Combine chunk text with its embedding for Supabase insert
const items = $input.all();
const chunks = $('Разбить на чанки').all();

return items.map((item, i) => ({
  json: {
    content: chunks[i]?.json?.text || '',
    metadata: chunks[i]?.json?.metadata || '{}',
    embedding: JSON.stringify(item.json.data[0].embedding)
  }
}));

// Ensure at least 1 item passes through even if search returned empty
const items = $input.all();
if (items.length === 0) {
  return [{json: {content: '', similarity: 0, _empty: true}}];
}
return items.map(item => ({json: item.json}));

